[
 {
  "criterion": "L1: Language Clarity, Precision, and Academic Tone",
  "explanation": "Evaluates the accuracy and fluency of sentence construction, grammar, spelling, and punctuation. Assesses the precise, consistent, and appropriate use of technical terminology related to AI, labor markets, the Fourth Industrial Revolution, and specific industries. Ensures an objective, formal academic tone suitable for a literature review. For example, terms like 'skill-biased technical change' or specific AI techniques should be used correctly and, if necessary, briefly contextualized for a broader academic audience.",
  "weight": 0.2
 },
 {
  "criterion": "S1: Overall Structure and Logical Organization",
  "explanation": "Assesses the coherence and logic of the review's macro-structure. This includes a clear introduction defining the review's scope, purpose, and organizational map; logically sequenced thematic sections with informative headings that reflect the facets of AI's impact on labor (e.g., by industry, skill level, type of disruption); and a conclusion that effectively synthesizes the main themes from the literature and perhaps points to gaps or future research directions.",
  "weight": 0.2
 },
 {
  "criterion": "S2: Paragraph Cohesion and Transitions",
  "explanation": "Evaluates if each paragraph focuses on a single, clear idea or theme derived from the literature, with sentences flowing logically within the paragraph. Assesses the effectiveness of transitional phrases, sentences, and logical connectors in linking ideas smoothly between paragraphs and across different sections of the review, ensuring a coherent narrative thread.",
  "weight": 0.15
 },
 {
  "criterion": "P1: Clarity and Synthesis in Presenting Sourced Information",
  "explanation": "Assesses how clearly, concisely, and accurately key arguments, findings, theories, and methodologies from the cited journal articles are presented. Evaluates the effectiveness of synthesizing information from multiple sources to build a coherent understanding of topics (e.g., AI's effect on job displacement vs. creation, or changes in skill demands across industries), rather than just serially summarizing individual papers. Checks for appropriate information density and avoidance of redundancy.",
  "weight": 0.15
 },
 {
  "criterion": "D1: Clarity of Data/Evidence Referenced or Summarized",
  "explanation": "Evaluates the clarity with which quantitative or qualitative data, empirical findings, or specific evidence from cited studies (e.g., statistics on automation rates, survey results on worker sentiment) are described, interpreted, or summarized within the review. If the review itself uses tables or figures to compile or synthesize information from sources (e.g., a summary table of key studies and their findings), assesses their clarity, labeling, and effectiveness in aiding comprehension.",
  "weight": 0.1
 },
 {
  "criterion": "F1: Formatting, Layout, and Visual Consistency",
  "explanation": "Evaluates the use of consistent and professional formatting (e.g., font choice and size, spacing, margins, heading styles) that enhances readability. Assesses the overall visual layout for ease of navigation and reduced reader fatigue, including clear paragraph breaks. Also considers the visual consistency and unobtrusive integration of in-text citations and the clarity of the bibliography's formatting, which contributes to the academic presentation.",
  "weight": 0.1
 },
 {
  "criterion": "A1: Audience Adaptation and Explanation of Terms",
  "explanation": "Assesses if the language, level of detail, and style of argumentation are appropriate for an academic audience interested in AI's impact on the labor market. Evaluates whether potentially ambiguous or highly specialized terms are sufficiently contextualized or briefly explained to ensure understanding by readers who may not be experts in every specific sub-domain discussed (e.g., specific AI algorithms or niche economic theories).",
  "weight": 0.1
 }
]

